/**
 * Pride visual themes — 180 designed-by-parallel-subagent variations
 * for the HTML org chart. Each render picks a random theme so the
 * user gets a different visual story every time — like opening a
 * magazine and finding a fresh masthead each issue.
 *
 * Generated by scripts/build-pride-themes.mjs from .workflow-result.json.
 * To regenerate after a re-brainstorm, run:
 *   node scripts/build-pride-themes.mjs
 *
 * The renderer (pride-html.ts) plugs these directly into CSS — no
 * theme has any HTML-structural impact, only visual. Mascot themes
 * light up a lion PNG slot when assets/mascots/ contains PNGs;
 * otherwise fall back to the 🦁 emoji rendered via the OS font.
 *
 * Locked rule: leadBadgeText NEVER contains "MANAGER" — Brigade's
 * brand is "no managers, just leads and the team". The subagent
 * prompt enforced this; we also defensively normalise at gen time.
 */

export interface PridePalette {
  bg: string;
  cardBg: string;
  cardBorder: string;
  cardShadow: string;
  name: string;
  role: string;
  accent: string;
  headerText: string;
  taunt: string;
  spine: string;
  badgeBg: string;
  badgeText: string;
  blockBg: string;
  blockBorder: string;
  avatarBg: string;
  avatarBorder: string;
  footer: string;
  story: string;
}

export interface PrideFonts {
  body: string;
  display: string;
  mono: string;
}

export type CardShadowStyle = "none" | "subtle" | "pronounced" | "glow" | "hard";
export type HeaderStyle = "centered" | "banner" | "magazine" | "logo";
export type SpineStyle = "thin" | "thick" | "dotted" | "dashed" | "none";
export type AvatarStyle = "circle" | "square" | "rounded" | "hexagon";
export type BackgroundPattern = "none" | "dots" | "grid" | "noise" | "lines";

export interface PrideDecorations {
  cardRadius: number;
  cardShadowStyle: CardShadowStyle;
  cardBorderWidth: number;
  headerStyle: HeaderStyle;
  spineStyle: SpineStyle;
  avatarStyle: AvatarStyle;
  leadBadgeText: string;
  backgroundPattern: BackgroundPattern;
}

export interface PrideTheme {
  id: string;
  name: string;
  family: string;
  description: string;
  palette: PridePalette;
  fonts: PrideFonts;
  decorations: PrideDecorations;
  mascot: boolean;
}

