/**
 * Pick a random theme by rng. Same seed → same pick → idempotent caches.
 * Stable across builds because the array order is fixed.
 */
export function pickPrideTheme(rng: () => number = Math.random): PrideTheme {
  const idx = Math.floor(rng() * PRIDE_THEMES.length);
  return PRIDE_THEMES[idx] ?? PRIDE_THEMES[0]!;
}

/** Look up a theme by id (returns undefined for unknown). */
export function getPrideTheme(id: string): PrideTheme | undefined {
  return PRIDE_THEMES.find((t) => t.id === id);
}

/** Number of themes available — useful for diagnostics + tests. */
export const PRIDE_THEME_COUNT = PRIDE_THEMES.length;
